import { cursor } from './stores/cursor';
import { difficulty } from './stores/difficulty';
import { gamePaused, gameWon } from './stores/game';
import { timer } from './stores/timer';
import { hints } from './stores/hints';
import { gameStore } from './gameStore';
import { generateSudoku } from './sudoku';
import { decodeSencode } from './sencode';

/**
 * Start new game with a generated sudoku
 *
 * @param {('veryeasy' | 'easy' | 'medium' | 'hard')} diff - Difficulty
 */
export function startNew(diff) {
	difficulty.set(diff);
	cursor.reset();
	timer.reset();
	hints.reset();

	// 生成数独并直接初始化 gameStore（避免双重初始化）
	const generatedGrid = generateSudoku(diff);
	gameStore.initGame(generatedGrid);

	// 监听游戏完成状态
	const unsubscribe = gameStore.getGame().subscribe(() => {
		const sudoku = gameStore.getGame().getSudoku();
		if (sudoku.isComplete()) {
			gameWon.set(true);
			if (unsubscribe) unsubscribe();
		}
	});

	location.hash = '';
}

/**
 * Start new game with a custom sudoku
 *
 * @param {string} sencode - Sencode to decode
 */
export function startCustom(sencode) {
	difficulty.setCustom();
	cursor.reset();
	timer.reset();
	hints.reset();

	// 解码自定义数独并直接初始化 gameStore
	const decodedGrid = decodeSencode(sencode);
	gameStore.initGame(decodedGrid);

	// 监听游戏完成状态
	const unsubscribe = gameStore.getGame().subscribe(() => {
		const sudoku = gameStore.getGame().getSudoku();
		if (sudoku.isComplete()) {
			gameWon.set(true);
			if (unsubscribe) unsubscribe();
		}
	});
}

/**
 * Pause the game
 */
export function pauseGame() {
	timer.stop();
	gamePaused.set(true);
}

/**
 * Resume (un-pause) the game
 */
export function resumeGame() {
	timer.start();
	gamePaused.set(false);
}

// 导出 gameStore 供 UI 组件使用
export { gameStore };

export default {
	startNew,
	startCustom,
	pause: pauseGame,
	resume: resumeGame,
	gameStore
};